import time
import can
import pytest

GW_EXTERIOR_LIGHTING_ID = 0x10F
GW_EXTERIOR_LIGHTING_DLC = 8

@pytest.fixture(scope="module")
def can_bus():
    bus = can.Bus(interface="vector", channel=0, bitrate=500000)
    yield bus
    bus.shutdown()

def collect_messages(bus, msg_id, duration_sec):
    messages = []
    start_time = time.time()
    while time.time() - start_time < duration_sec:
        msg = bus.recv(timeout=0.5)
        if msg and msg.arbitration_id == msg_id:
            messages.append(msg)
    return messages

def decode_headlamp(msg):
    return (msg.data[0] >> 0) & 0x01

def decode_tail_lamp(msg):
    return (msg.data[0] >> 1) & 0x01

def decode_hazard(msg):
    return (msg.data[0] >> 2) & 0x01

test_cases.python_test_script:
def test_tc_gw_lgt_001_message_present(can_bus):
    msgs = collect_messages(can_bus, GW_EXTERIOR_LIGHTING_ID, 2)
    assert msgs, 'GW_ExteriorLighting message not received'

def test_tc_gw_lgt_003_headlamp_on(can_bus):
    msgs = collect_messages(can_bus, GW_EXTERIOR_LIGHTING_ID, 2)
    assert msgs, 'No GW_ExteriorLighting messages received'
    for msg in msgs:
        assert decode_headlamp(msg) == 1

def test_tc_gw_lgt_004_tail_lamp_on(can_bus):
    msgs = collect_messages(can_bus, GW_EXTERIOR_LIGHTING_ID, 2)
    assert msgs, 'No GW_ExteriorLighting messages received'
    for msg in msgs:
        assert decode_tail_lamp(msg) == 1

def test_tc_gw_lgt_005_hazard_on(can_bus):
    msgs = collect_messages(can_bus, GW_EXTERIOR_LIGHTING_ID, 2)
    assert msgs, 'No GW_ExteriorLighting messages received'
    for msg in msgs:
        assert decode_hazard(msg) == 1

def test_tc_gw_lgt_006_head_and_tail_on(can_bus):
    msgs = collect_messages(can_bus, GW_EXTERIOR_LIGHTING_ID, 2)
    assert msgs, 'No GW_ExteriorLighting messages received'
    for msg in msgs:
        assert decode_headlamp(msg) == 1
        assert decode_tail_lamp(msg) == 1

def test_tc_gw_lgt_008_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_EXTERIOR_LIGHTING_ID, 2)
    assert msgs, 'No GW_ExteriorLighting messages received'
    for msg in msgs:
        assert msg.dlc == GW_EXTERIOR_LIGHTING_DLC
